import { describe, expect, it } from "vitest";
import { formatHeartbeat, formatNoProgressNotice, formatReplayCommandFailure, formatReplayHeader, formatReplayResultMissing, formatReplaySummary, formatTraceLine, } from "./replayProgressView.js";
describe("formatReplayHeader", () => {
    it("shows label and count when known, singularizes one trace", () => {
        expect(formatReplayHeader("generate-email", 20)).toBe("▶ generate-email · 20 traces");
        expect(formatReplayHeader("generate-email", 1)).toBe("▶ generate-email · 1 trace");
    });
    it("falls back gracefully when label or total is missing", () => {
        expect(formatReplayHeader("generate-email", undefined)).toBe("▶ generate-email · traces");
        expect(formatReplayHeader(undefined, 12)).toBe("▶ 12 traces");
        expect(formatReplayHeader(undefined, undefined)).toBe("▶ traces");
    });
});
describe("formatTraceLine", () => {
    function event(completed, total, item) {
        const errored = item?.error ? 1 : 0;
        return { completed, total, succeeded: completed - errored, errored, item };
    }
    it("renders a passing trace with glyph, n/total, and its duration", () => {
        expect(formatTraceLine(event(5, 12, { traceId: "t5", error: null, durationMs: 1100 }))).toBe("  ✓ 5/12 · 1.1s");
    });
    it("renders a failing trace with the reason after the duration", () => {
        expect(formatTraceLine(event(4, 12, {
            traceId: "t4",
            error: "missing OPENAI_API_KEY",
            durationMs: 200,
        }))).toBe("  ✗ 4/12 · 0.2s · missing OPENAI_API_KEY");
    });
    it("omits the duration segment when it is unknown", () => {
        expect(formatTraceLine(event(3, 12, { traceId: "t3", error: null }))).toBe("  ✓ 3/12");
    });
    it("uses the first non-empty line of a multi-line error", () => {
        expect(formatTraceLine(event(2, 12, {
            traceId: "t2",
            error: "\nrate_limit_exceeded\n  at foo()",
            durationMs: 300,
        }))).toBe("  ✗ 2/12 · 0.3s · rate_limit_exceeded");
    });
});
describe("formatHeartbeat", () => {
    it("shows the running count and whole-second elapsed", () => {
        expect(formatHeartbeat(4, 12, 38_400)).toBe("  … 4/12 running · 38s elapsed");
    });
    it("drops the count when the total is unknown (run still starting up)", () => {
        expect(formatHeartbeat(0, 0, 12_000)).toBe("  … running · 12s elapsed");
    });
});
describe("formatReplaySummary", () => {
    it("✓ when all ran, with wall time and average per-trace time", () => {
        expect(formatReplaySummary({
            completed: 12,
            errored: 0,
            elapsedMs: 12400,
            sumDurationMs: 13200,
        })).toBe("  ✓ done · 12 ok · 12.4s · avg 1.1s");
    });
    it("⚠ and a failed count when some errored", () => {
        expect(formatReplaySummary({
            completed: 12,
            errored: 2,
            elapsedMs: 12400,
            sumDurationMs: 13200,
        })).toBe("  ⚠ done · 10 ok · 2 failed · 12.4s · avg 1.1s");
    });
    it("drops the average when no per-trace durations were seen", () => {
        expect(formatReplaySummary({ completed: 4, errored: 0, elapsedMs: 2000 })).toBe("  ✓ done · 4 ok · 2.0s");
    });
});
describe("formatReplayCommandFailure", () => {
    it("shows the exit code and result path after progress was reported", () => {
        expect(formatReplayCommandFailure({
            code: 7,
            signal: null,
            out: "scripts/replay-result.json",
        })).toBe("  ✗ failed (exit 7) · replay command exited non-zero · check scripts/replay-result.json");
    });
    it("names the signal when the replay process was killed", () => {
        expect(formatReplayCommandFailure({
            code: null,
            signal: "SIGTERM",
            out: "out.json",
        })).toBe("  ✗ failed (signal SIGTERM) · replay command exited non-zero · check out.json");
    });
});
describe("formatReplayResultMissing", () => {
    it("points at the missing result path", () => {
        expect(formatReplayResultMissing("scripts/replay-result.json")).toBe("  ✗ failed · replay finished without ReplayResult JSON · check scripts/replay-result.json");
    });
});
describe("formatNoProgressNotice", () => {
    it("⚠ when the replay ran but reported nothing (old SDK / unwired onProgress)", () => {
        expect(formatNoProgressNotice({
            failed: false,
            code: 0,
            signal: null,
            out: "scripts/replay-result.json",
        })).toBe("  ⚠ done · replay finished but reported no progress · its @bitfab/sdk predates progress reporting, or onProgress isn't wired");
    });
    it("✗ with the exit code and the result path when the replay failed", () => {
        expect(formatNoProgressNotice({
            failed: true,
            code: 5,
            signal: null,
            out: "scripts/replay-result.json",
        })).toBe("  ✗ failed (exit 5) · no progress reported · check scripts/replay-result.json");
    });
    it("names the signal when the replay was killed", () => {
        expect(formatNoProgressNotice({
            failed: true,
            code: null,
            signal: "SIGTERM",
            out: "out.json",
        })).toBe("  ✗ failed (signal SIGTERM) · no progress reported · check out.json");
    });
});
